class Solution:
    def maximumCoins(self, coins, k):
        if not coins:
            return 0
        lo = min(c[0] for c in coins)
        hi = max(c[1] for c in coins)
        span = hi - lo + 1
        arr = [0] * span
        for l, r, c in coins:
            for x in range(l, r + 1):
                arr[x - lo] += c
        pad = k
        ext = [0] * (span + 2 * pad)
        for i, v in enumerate(arr):
            ext[i + pad] = v
        best = 0
        cur = sum(ext[0:k])
        best = cur
        for start in range(1, len(ext) - k + 1):
            cur += ext[start + k - 1] - ext[start - 1]
            best = max(best, cur)
        return best

