var maximumCoins = function(coins, k) {
    const sorted = coins.slice().sort((a, b) => a[0] - b[0]);
    const n = sorted.length;
    const L = sorted.map(c => c[0]);
    const R = sorted.map(c => c[1]);
    const C = sorted.map(c => c[2]);
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + C[i] * (R[i] - L[i] + 1);

    function lowerBound(arr, target) {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < target) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    function upperBound(arr, target) {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] <= target) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    function windowSum(start, end) {
        if (start > end) return 0;
        const idx = lowerBound(R, start);
        if (idx === n || L[idx] > end) return 0;
        const lo = Math.max(start, L[idx]);
        const hi = Math.min(end, R[idx]);
        let total = (hi - lo + 1) * C[idx];
        const idx2 = upperBound(L, end) - 1;
        if (idx2 > idx) {
            total += prefix[idx2] - prefix[idx + 1];
            const lo2 = L[idx2];
            const hi2 = Math.min(end, R[idx2]);
            total += (hi2 - lo2 + 1) * C[idx2];
        }
        return total;
    }
    let best = 0;
    for (let i = 0; i < n; i++) {
        best = Math.max(best, windowSum(L[i], L[i] + k - 1));
        best = Math.max(best, windowSum(R[i] - k + 1, R[i]));
    }
    return best;
};
